import * as React from 'react';
import { createComponent } from '../create-component.js';
import Component from '../../components/breadcrumb/src/breadcrumb.component.js';
const tagName = 'made-breadcrumb';
Component.define('made-breadcrumb');
/**
 * @summary The Breadcrumb component provides a navigation trail for users, showing their current location within a hierarchy.
 * @documentation '../../components/breadcrumb/stories/breadcrumb.mdx'
 *
 * @slot - One or more made-breadcrumb-item elements.
 *
 * @csspart base - The component's base wrapper.
 * @csspart list - The wrapper around the list of breadcrumb items.
 * @csspart item - The wrapper around an individual breadcrumb item.
 * @csspart separator - The separator between breadcrumb items.
 */
const reactWrapper = createComponent({
    tagName,
    elementClass: Component,
    react: React,
    events: {},
    displayName: 'MadeBreadcrumb'
});
export default reactWrapper;
